<template><div class="app"><component :is="page"/><BottomNav v-if="showBottomNav"/></div></template><script setup lang="ts">import{computed,h}from'vue';import{route,showBottomNav}from'./router';import BottomNav from'./components/BottomNav.vue';import HomePage from'./pages/HomePage.vue';import MessagesPage from'./pages/MessagesPage.vue';import MessageDetailPage from'./pages/MessageDetailPage.vue';import ModulePage from'./pages/ModulePage.vue';const modules:any={orders:['订单','查看与处理订单'],products:['商品','管理商品与库存'],finance:['财务','查看交易与财务流水'],settings:['设置','管理卖家后台设置']};const page=computed(()=>{if(route.value.path==='/')return HomePage;if(route.value.path==='/messages')return MessagesPage;if(route.value.chatId)return MessageDetailPage;const k=route.value.path.split('/')[1],m=modules[k]||['页面',''];return{render:()=>h(ModulePage,{title:m[0],help:m[1]})}})</script>
